#include <stdio.h>
#include <string.h>

int main() {
    char A[105], B[105];
    int ans[106] = {0};
    scanf("%s %s", A, B);

    int lenA = strlen(A);
    int lenB = strlen(B);
    int i = lenA - 1;
    int j = lenB - 1;
    int k = 0;
    int carry = 0;

    while (i >= 0 || j >= 0 || carry) {
        int sum = carry;
        if (i >= 0) sum += A[i--] - '0';
        if (j >= 0) sum += B[j--] - '0';
        ans[k++] = sum % 10;
        carry = sum / 10;
    }

    for (int idx = k - 1; idx >= 0; idx--) {
        printf("%d", ans[idx]);
    }
    printf("\n");
    return 0;
}

