#include <stdio.h>

int main() {
    int n;
    int next_room[1005];
    int visited[1005] = {0};

    scanf("%d", &n);
    for (int i = 1; i <= n; i++) {
        scanf("%d", &next_room[i]);
    }

    int current = 1;
    while (1) {
        if (visited[current] == 1) {
            printf("CYCLE\n");
            return 0;
        }
        visited[current] = 1;
        current = next_room[current];

        if (current < 1 || current > n) {
            printf("EXIT\n");
            return 0;
        }
    }
    return 0;
}

